  // Article body (static content)
  "article.body1": { id: "Di era digital saat ini, memilih laptop yang tepat menjadi keputusan penting bagi setiap profesional.", en: "In today's digital era, choosing the right laptop is a crucial decision for every professional." , ru: "В современную цифровую эпоху выбор подходящего ноутбука является решающим решением для каждого профессионала.", zh: "在当今数字时代，选择合适的笔记本电脑对每位专业人士来说都是一项至关重要的决定。" },
  "article.body2": { id: "Mengapa Pemilihan Laptop Itu Penting?", en: "Why Is Choosing the Right Laptop Important?" , ru: "Почему выбор правильного ноутбука важен?", zh: "为什么选择合适的笔记本电脑很重要？" },
  "article.body3": { id: "Laptop bukan sekadar alat kerja, tapi partner produktivitas Anda sehari-hari.", en: "A laptop isn't just a work tool, it's your daily productivity partner." , ru: "Ноутбук — это не просто рабочий инструмент, это ваш ежедневный партнер по продуктивности.", zh: "笔记本电脑不仅仅是工作工具，更是您日常生产力的伙伴。" },
  "article.body4": { id: "Kriteria Laptop untuk Remote Work", en: "Laptop Criteria for Remote Work" , ru: "Критерии выбора ноутбука для удаленной работы", zh: "远程工作的笔记本电脑标准" },
  "article.body5": { id: "Ada beberapa kriteria utama yang harus diperhatikan saat memilih laptop untuk bekerja remote.", en: "There are several key criteria to consider when choosing a laptop for remote work." , ru: "Есть несколько ключевых критериев, которые следует учитывать при выборе ноутбука для удаленной работы.", zh: "选择一台适合远程工作的笔记本电脑时，有几个关键标准需要考虑。" },
  "article.body6": { id: "Kesimpulan", en: "Conclusion" , ru: "Заключение", zh: "总结" },
  "article.body7": { id: "Investasi pada laptop yang tepat adalah investasi untuk produktivitas jangka panjang Anda.", en: "Investing in the right laptop is an investment in your long-term productivity." , ru: "Инвестиции в правильный ноутбук — это инвестиции в вашу долгосрочную продуктивность.", zh: "投资一台合适的笔记本电脑就是投资您的长期生产力。" },

